def check_cost_limits():
    client = boto3.client('ce')

    response = client.get_cost_and_usage(
        TimePeriod={
            'Start': '2023-10-01',
            'End': '2023-10-31'
        },
        Granularity='MONTHLY',
        Metrics=['UNBLINED_COST']
